// import { mls } from "../index"; // error on ServiceWorker if imported
let dbOrNull = null;
const dbName = "mlsSW";
const version = 4; // Increment the DB version for each new table created, modified, or deleted.
const initDB = async () => {
    return new Promise((resolve, reject) => {
        if (dbOrNull) {
            resolve(dbOrNull);
            return;
        }
        const request = indexedDB.open(dbName, version);
        request.onblocked = () => console.warn('[IDB] Upgrade blocked');
        request.onerror = () => reject(request.error);
        request.onupgradeneeded = (event) => {
            const db = event.target.result;
            db.onversionchange = () => {
                try {
                    db.close();
                }
                catch {
                    console.log('[IDB] Error closing DB');
                }
            };
            dbOrNull = db;
            if (!db.objectStoreNames.contains("serviceWorker")) {
                db.createObjectStore("serviceWorker", { keyPath: "key" });
            }
            if (!db.objectStoreNames.contains("tsWorker")) {
                db.createObjectStore("tsWorker", { keyPath: "key" });
            }
            if (!db.objectStoreNames.contains("notifications")) {
                db.createObjectStore("notifications", { keyPath: "key" });
            }
        };
        request.onsuccess = (event) => {
            const db = event.target.result;
            dbOrNull = db; // cache the instance
            resolve(db);
        };
    });
};
export const set = async (tbName, key, value) => {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(tbName, "readwrite");
        const objectStore = transaction.objectStore(tbName);
        const request = !value ? objectStore.delete(key) : objectStore.put({ key, value });
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
        request.onerror = () => reject(request.error);
    });
};
export const setMultiple = async (tbName, keys, values) => {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(tbName, "readwrite");
        const objectStore = transaction.objectStore(tbName);
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
        keys.forEach((key, index) => {
            const value = values[index];
            const request = value === "" ? objectStore.delete(key) : objectStore.put({ key, value });
            request.onerror = () => reject(request.error);
        });
    });
};
export const get = async (tbName, key) => {
    const db = await initDB();
    return new Promise((resolve) => {
        const transaction = db.transaction(tbName, "readonly");
        const objectStore = transaction.objectStore(tbName);
        const request = objectStore.get(key);
        request.onsuccess = () => resolve(request.result?.value);
        request.onerror = () => resolve(undefined);
    });
};
export const getAll = async (tbName) => {
    const db = await initDB();
    return new Promise((resolve) => {
        const transaction = db.transaction(tbName, "readonly");
        const objectStore = transaction.objectStore(tbName);
        const request = objectStore.getAll();
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => resolve([]);
    });
};
export const clear = async (tbName) => {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(tbName, "readwrite");
        transaction.onerror = () => resolve(undefined);
        const objectStore = transaction.objectStore(tbName);
        const request = objectStore.clear();
        request.onsuccess = () => resolve(undefined);
        request.onerror = () => resolve(undefined);
    });
};
export const readRecordsInProject = async (project, extension) => {
    const tbName = "serviceWorker";
    const prefix = "/local/_" + project + "_";
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(tbName, 'readonly');
        const store = transaction.objectStore(tbName);
        const keyRange = IDBKeyRange.bound(prefix, prefix + '\uffff');
        const cursorRequest = store.openCursor(keyRange);
        const records = [];
        cursorRequest.onsuccess = (event) => {
            const cursor = event.target.result;
            // {key: '/local/_100554_ateste.js', value: '20240216130526679'}
            if (cursor) {
                const key = cursor.value.key.trim();
                const value = cursor.value.value.trim();
                // console.log(`readRecordsInProject, project: ${project}, extension: "${extension}", key: "${key}", value: "${value}" ${key.endsWith(extension)}`);
                if (key.endsWith(extension)) {
                    let shortName = key.substring(prefix.length);
                    shortName = shortName.substring(0, shortName.length - extension.length); // remove extension
                    records.push({
                        project,
                        shortName,
                        extension,
                        changedAt: value || "00000000000000000"
                    });
                }
                cursor.continue();
            }
            else {
                resolve(records);
            }
        };
        cursorRequest.onerror = (event) => {
            console.error('Error reading records:', event?.target?.error || "?");
            resolve(records);
        };
    });
};
export const getLocalCacheKey = (project, folder, shortName, extension) => {
    return `/local/_${project}_${folder ? `${folder}/` : ''}${shortName}${extension}`;
};
/**
 * return localShortPath, value
 * localShortPath ex '/local/_100554_ateste.js'
 * value ex '20240216130526679' (versionRef)
 * @param project project number or null for all projects
 */
export const getAllFilesRefInCache = async (project) => {
    const tbName = "serviceWorker";
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(tbName, "readonly");
        const objectStore = transaction.objectStore(tbName);
        const prefix = project ? `/local/_${project}_` : `/local/_`;
        const range = IDBKeyRange.bound(prefix, prefix + '\uffff');
        const request = objectStore.getAll(range);
        request.onsuccess = (event) => {
            resolve((event.target.result ?? []));
        };
        request.onerror = (event) => {
            reject(event.target.error);
        };
    });
};
// eslint-disable-next-line @shopify/no-fully-static-classes
export class notificationStore {
    static async save(notification) {
        return set(this.tbName, notification.id, JSON.stringify(notification));
    }
    static async getAll() {
        const results = await getAll(this.tbName);
        return results.map(({ key, value }) => {
            const notification = JSON.parse(value);
            return notification;
        });
    }
    static async delete(id) {
        await set(this.tbName, id, null);
    }
    static async markSending(id) {
        const raw = await get(this.tbName, id);
        if (!raw)
            return;
        const rec = JSON.parse(raw);
        if (rec) {
            rec.attempts++;
            if (rec.attempts > 3) {
                await set(this.tbName, id, null); // delete
            }
            else {
                await set(this.tbName, id, JSON.stringify(rec));
            }
        }
    }
}
notificationStore.tbName = "notifications";
