self.addEventListener('push', (event: PushEvent) => {
  if (mls.isTrace) console.info('[ServiceWorker] Push event received:', event);

  event.waitUntil((async () => {
    let payload: any = {};
    try {
      // If payload is { data: {...} }, keep ".data". If not, use the whole JSON.
      const raw = event.data?.json?.() ?? {};
      payload = raw.data ?? raw;
    } catch (e) {
      console.warn('[ServiceWorker] Failed to parse push data', e);
      return;
    }

    if (payload?.type === 'thread-update') {
      await saveNotification('thread-update', payload);
    } else {
      console.warn('[SW] Unhandled push type:', payload?.type);
    }
    // No user-visible notification: silent sync
  })());
});

const saveNotification = async (type: string, data: any): Promise<void> => {
  // save notification to indexed DB
  const rec: serviceWorkerIndex.Notifications = {
    type,
    data,
    id: `${Date.now()}#${Math.random().toString(36).slice(2, 8)}`,
    attempts: 0
  };
  serviceWorkerIndex.notificationStore.save(rec);
  notifyAllClients(rec);
}

/**
 * Send all past notifications to clients.
 * Used after a page requests to receive old messages.
 */
const sendNotificationsRequestMissed = async (): Promise<void> => {
  serviceWorkerIndex.notificationStore.getAll().then((notifications: serviceWorkerIndex.Notifications[]) => {
    notifications.forEach(notification => {
      notifyAllClients(notification);
    });
  });
}

/**
 * Used after a page confirms the receipt of a notification.
 */
const receiveACK = async (id?: string) => {
  if (!id) {
    console.log(`[ServiceWorker] ACK received without ID`);
  } else {
    serviceWorkerIndex.notificationStore.delete(id);
  }
}

// Function to notify all clients
const notifyAllClients = async (notification: serviceWorkerIndex.Notifications): Promise<void> => {
  const clients = await self.clients.matchAll({ includeUncontrolled: true });
  if (!clients || clients.length === 0) {
    return;
  }
  if (mls.isTrace) console.log(`[ServiceWorker] Notifying all clients: ${notification.type}`, notification.data, clients);
  serviceWorkerIndex.notificationStore.markSending(notification.id); // add attempts, delete notification if attempts > 3
  clients.forEach(client => {
    client.postMessage(notification);
  });
};

