let baseProject: number = 0;

const getProjectId = async (event: FetchEvent): Promise<void> => {
  if (event.request.method !== 'POST') return;
  const clone = event.request.clone();
  try {
    const data = await clone.json();
    if (mls.isTrace) console.log('[ServiceWorker] getProjectId, data:', data);
    if (!data || !data.baseProject) {
      if (mls.isTrace) console.warn('[ServiceWorker] getProjectId, no baseProject in data');
      return;
    }
    baseProject = Number(data.baseProject);
    if (Number.isNaN(baseProject) || baseProject < 1) baseProject = 0;
  } catch (err) {
    console.error('Failed to parse JSON:', err);
  }
};

let fetchCount = 0;
const prefixWidgetName = "/_";
const getLocalFiles = async (event: FetchEvent, url: string, uri: URL): Promise<Response> => {
  let path = uri.pathname;
  const version = uri.searchParams.get('v');
  // use cache situations:
  // - to files in mls.stor.files , ex: [path]?v=[version]
  // - to import javascript in preview, ex: _100111_widget1
  //

  // import { x } from "./l2/localteste"; -> localCache2, get base project
  // import { x } from “_100554_/l2/externalteste"; -> isExternalCache
  // import { x } from "_102019_mdm_organismEditContact" -> /local/_102019_mdm/organismEditContact -> folders

  const isLocalCache: boolean = (path.startsWith('/local/'));
  const localCache2Prefix = path.startsWith('/l2/') ? '/l2' : path.startsWith('/l1/') ? '/l1' : '';
  const isLocalCache2: boolean = Boolean(localCache2Prefix);
  const isExternalCache: boolean = isLocalCache2 ? false : path.includes('/l2/') || path.includes('/l1/'); // ex: /_100554_/l2/externalteste.js
  let project: number = 0;
  let widgetName: string | null = null;
  // const isTestFile = path.endsWith('.test.js');
  // const isDefsFile = path.endsWith('.defs.js');
  const isJsFile = path.endsWith('.js');
  // const isTsFile = path.endsWith('.ts');
  const withNoExtension = !path.includes('.');
   // if ((isTestFile || isDefsFile || withNoExtension) && !version) {
  if ((isJsFile || withNoExtension) && !version) {
    if (isLocalCache) {
      path = path.substring('/local'.length);
      if (mls.isTrace) console.log(`[ServiceWorker] getLocalFiles localCache, baseProject=${baseProject}, path=${path}`);
    } else if (isLocalCache2) {
      path = path.substring(localCache2Prefix.length);
      if (!path.startsWith('/_')) {
        project = baseProject;
        widgetName = `${path.substring(1)}`;
      }
      if (mls.isTrace) console.log(`[ServiceWorker] getLocalFiles localCache2, baseProject=${baseProject}, path=${path}, project=${project}, widgetName=${widgetName}`);
    } else if (isExternalCache) {
      path = path.replace('/l2/', '').replace('/l1/', '');
      if (mls.isTrace) console.log(`[ServiceWorker] getLocalFiles externalCache, path=${path}`);
    }
    // - to import javascript in preview, ex: _100111_widget1
    if (!widgetName && path.startsWith(prefixWidgetName)) {
      // /_100111_folder1_folder2_widget1
      let rest = path.substring(prefixWidgetName.length);
      const firstUnderscore = rest.indexOf("_");
      project = Number(rest.substring(0, firstUnderscore));

      // const ar: string[] = path.substring(prefixWidgetName.length).split("_");
      // project = Number(ar[0]);
      // ar.shift();
      if (project > 0 && project < 999999999999) {
        widgetName = rest.substring(firstUnderscore + 1);
        // widgetName = ar.join("/"); // widgetName = 'folder1/folder2/widget1'
        if (widgetName.startsWith("/")) {
          widgetName = widgetName.substring(1);
        }
        if (mls.isTrace && widgetName.includes("/")) console.log(`[ServiceWorker] getLocalFiles with folders, project=${project}, widgetName=${widgetName}`);
      }
    }
  }

  if (!isLocalCache && !widgetName) return fetch(event.request); // return without fetching, don't show 2x in devtools tab

  // Runtime VM (non-studio host): the same /_<id>_/l2/*.js URLs exist BOTH in
  // the SW cache (studio sources delivered by the cbe login) and on the server
  // (the app release, dist/web). The release must win — otherwise a publish is
  // shadowed by a stale studio cache. Network-first with cache fallback here;
  // versioned requests (?v=) stay cache-first everywhere (studio-edited files).
  const isStudioHost = self.location.host === 'multilevelstudio.com'
    || self.location.host === 'collab.codes'
    || self.location.host.endsWith('.collab.codes');
  if (!isStudioHost && !uri.searchParams.get('v')) {
    try {
      const networkResponse = await fetch(event.request.url, { cache: 'no-cache' });
      if (networkResponse && networkResponse.ok) return networkResponse;
    } catch {
      // offline or server unreachable: fall back to the cache below
    }
  }

  // in this point widgetName = "widget1"
  if (widgetName) url = (await findCacheJS(project, widgetName)) || url;

  const cachedResponse = await caches.match(url);
  if (cachedResponse) {
    totalHits += 1;
    return cachedResponse;
  }
  totalNotFound += 1;
  // Cache miss: fall back to the network. On the runtime VM the app's own
  // modules use the same /_<id>_/ URL shape and are served by the 102034
  // server (dist/web) — the studio server answers 404 for them anyway, so
  // studio behavior is unchanged.
  try {
    return await fetch(event.request);
  } catch {
    // offline or server unreachable: keep the synthetic 404
  }
  return new Response(null, {
    status: 404,
    statusText: 'file in local cache Not Found, url=' + url
  });

};

/**
 * Removes all files with the same path from the cache.
 */
const removeOldCache = async (cache: Cache, path: string): Promise<void> => {
  // path start with "_" and contains extension
  const match = await cache.match(path, { ignoreSearch: true, ignoreMethod: true, ignoreVary: true });
  if (match) {
    cache.delete(path, { ignoreSearch: true, ignoreMethod: true, ignoreVary: true });
  }
};

/**
 * Delete and put a new file in the cache with same version
 * or just delete if content is null
 * or just put if not in cache
 */
const updateCache = async (cache: Cache, pathWithVersion: string, request: Request, response: Response, onlyDelete: boolean): Promise<boolean | void> => {
  // pathWithVersion ex: /local/_100111_myFile.xx?v=123
  const match = await cache.match(pathWithVersion);
  if (match) {
    if (mls.isTrace) console.log(`[ServiceWorker]updateCache: not changed ${pathWithVersion}, onlyDelete=${onlyDelete}`, match);
    if (onlyDelete) return cache.delete(pathWithVersion, { ignoreSearch: true, ignoreMethod: true, ignoreVary: true });
    return true; // not changed
  }
  if (mls.isTrace) console.log(`[ServiceWorker] updateCache: changed ${pathWithVersion}, onlyDelete=${onlyDelete}`);
  if (!onlyDelete) return cache.put(request, response)
  return true;
}

/**
 * Add a file to the cache.
 *
 * @param {ServiceWorkerMessage} message - The message object from the client containing the path, version and contents of file to be added.
 * @returns {Promise<void>} A promise that resolves when the file has been added to the cache.
 */
const add = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<string> => {
  if (typeof message.path !== 'string') throw new Error('incorrect message in add, path must be string');
  if (typeof message.version !== 'string') throw new Error('incorrect message in add, version must be string');
  if (typeof message.contentType !== 'string') throw new Error('incorrect message in add, contentType must be string');
  if (typeof message.content !== 'string' &&
    typeof message.content !== 'object') throw new Error('incorrect message in add, content must be string or Blob');
  if (
    (typeof message.content === 'string' && !(message.content as string).length) ||
    (typeof message.content === 'object' && !(message.content as Blob).size) ||
    !message.path ||
    !message.version) throw new Error('incorrect message in add');
  const content: string | Blob = message.content as string | Blob;
  if (!message.path.startsWith("_")) throw new Error('incorrect message in add, FileName must start with project');
  const cache = await caches.open(CACHE_NAME);
  // message.path ex: `_${project}_${folder ? `${folder}/` : ''}${shortName}${extension}`
  await removeOldCache(cache, message.path);
  if (!message.content) return ""; // just erase entry
  const pathWithVersion = getPath(message.path, message.version);
  const request = new Request(pathWithVersion);
  const len: number = typeof message.content === 'string'
  ? (message.content ? (message.content as string).length : 0) : (message.content as Blob).size;

  const response = new Response(content, {
    headers: {
      'Content-Type': message.contentType || '',
      'Content-length': len.toString()
    },
  });
  totalInserts++;
  cacheIndex.addPath(message.path, message.version); // add for future search
  await cache.put(request, response);
  if (mls.isTrace) console.info(`[ServiceWorker] add  path=${pathWithVersion}, len=${len}`);
  return pathWithVersion;
};

/**
 * Add files to the cache.
 *
 * @param {ServiceWorkerMessage} message - The message object from the client containing the path, version and contents of file to be added.
 * @returns {Promise<void>} A promise that resolves when the file has been added to the cache.
 */
const adds = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<string> => {
  if (!Array.isArray(message.path)) throw new Error('incorrect message in adds, path must be array');
  if (!Array.isArray(message.version)) throw new Error('incorrect message in adds, version must be array');
  if (!Array.isArray(message.contentType)) throw new Error('incorrect message in adds, contentType must be array');
  if (!Array.isArray(message.content)) throw new Error('incorrect message in adds, content must be array');
  if (message.path.length !== message.version.length) throw new Error('incorrect message in adds, path and version must have the same length');
  if (message.path.length !== message.contentType.length) throw new Error('incorrect message in adds, path and contentType must have the same length');
  if (message.path.length !== message.content.length) throw new Error('incorrect message in adds, path and content must have the same length');

  const filesToUpdate: { request: Request, response: Response, pathWithVersion: string, onlyDelete: boolean }[] = [];
  // Pre-fetch all cache versions for paths that are version dates
  const cacheVersionPromises: Array<Promise<string | undefined> | undefined> = message.path.map((path, i) => {
    const version = message.version?.[i] || "";
    const isVersionDate = ((version.length === 24) && (version[4] === '-') && (version[7] === '-') && (version[10] === 'T'));
    if (isVersionDate) {
      return cacheIndex.getVersionFromPath(path);
    }
    return undefined;
  });
  const cacheVersions = await Promise.all(cacheVersionPromises);

  for (let i = 0; i < message.path.length; i++) {
    const path = message.path[i];
    const version = message.version[i];
    const contentType = message.contentType[i];
    const content: string | Blob = message.content[i] as string | Blob;
    if (
      (typeof content === 'string' && !(content as string).length) ||
      (typeof content === 'object' && !(content as Blob).size) ||
      !path ||
      !version) throw new Error(`incorrect message in add, index ${i}`);
    if (!path.startsWith("_")) throw new Error('incorrect message in add, FileName must start with project');
    // verify .js cache local is more actual than request
    const isVersionDate = ((version.length === 24) && (version[4] === '-') && (version[7] === '-') && (version[10] === 'T')); // iso date
    if (isVersionDate) {
      const cacheVersion = cacheVersions[i];
      const isVersionInCacheDate = (cacheVersion && (cacheVersion.length === 24) && (cacheVersion[4] === '-') && (cacheVersion[7] === '-') && (cacheVersion[10] === 'T'));
      if (isVersionInCacheDate && cacheVersion! >= version) {
        if (mls.isTrace) console.info(`[ServiceWorker] Skipping: JS cache is more recent. Path=${path}, version=${version}, cacheVersion=${cacheVersion}`);
        continue;
      }
    }
    const pathWithVersion = getPath(path, version);
    const request: Request = new Request(pathWithVersion);
    const len: number = typeof content === 'string'
      ? (content ? (content as string).length : 0) : (content as Blob).size;
    const response: Response = new Response(message.content[i], {
      headers: {
        'Content-Type': contentType || '',
        'Content-length': len.toString()
      },
    });
    totalInserts++;
    filesToUpdate.push({ request, response, pathWithVersion, onlyDelete: (!content) });
  }

  const cache = await caches.open(CACHE_NAME);
  await Promise.allSettled(filesToUpdate.map(item => updateCache(cache, item.pathWithVersion, item.request, item.response, item.onlyDelete)));
  await cacheIndex.addPaths(message.path, message.version); // add for future search

  return filesToUpdate.map(item => item.pathWithVersion).join(",");
};

/**
 * Clears all files from the cache.
 * @param {ServiceWorkerMessage} message - The message sent from the main thread to the Service Worker.
 */
const clearAll = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<void> => {
  const cache = await caches.open(CACHE_NAME);
  await cache.keys().then(keys => Promise.all(keys.map(key => cache.delete(key))));
  cacheIndex.clear();
};

/** clear all obsolete cache in DB cache
 * compare with indexedDB and delete if not in indexedDB
 */
const clearObsolete = async (): Promise<void> => {
  // get all keys in indexedDB
  const allKeys: serviceWorkerIndex.IFilesRefInCache[] = await cacheIndex.getAllFilesRefInCache(null);
  // convert to cache url
  const urls: string[] = allKeys.map(item => cacheIndex.getCacheUrl(item));
  const cache = await caches.open(CACHE_NAME);
  const keys = await cache.keys();

  function goodToDelete(url: string): boolean {
    const uri = new URL(url);
    if (urls.includes(uri.pathname + uri.search)) return false; // active in indexedDB
    if (uri.pathname.endsWith('.js')) {
      const tsName = uri.pathname.replace('.js', '.ts');
      const keyIDB = allKeys.find(item => item.key === tsName);
      const isOriginalVersion = (`?v=${keyIDB?.value}` === uri.search);
      if (keyIDB && isOriginalVersion) return false; // .ts active in indexedDB
    }
    return true; // ok to delete
  }

  const keysToDelete = keys.filter(key => goodToDelete(key.url));
  if (keysToDelete.length === 0) return;
  await Promise.all(keysToDelete.map(key => cache.delete(key)));
  if (mls.isTrace) console.log(`[ServiceWorker] clear cache Obsolete finish, records deleted=`, keysToDelete.length);
}

/**
 * clear all cache from a project
 */
const clearProjects = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<void> => {
  // message path ex: ['100111, 100112']
  let projects: string[] = [];
  if (typeof message.path === 'string') projects = [message.path];
  else if (Array.isArray(message.path)) projects = message.path;
  else throw new Error('incorrect message in clearProject, path must be string or array');
  for await (const prj of projects) {
    const projectID: number = Number(prj) || 0;
    await clearProject(projectID);
  }
  if (mls.isTrace) console.log(`[ServiceWorker] clearProjects finish: projects length=`, projects.length);
}

const clearProject = async (projectID: number): Promise<void> => {
  if (projectID < 1) throw new Error('incorrect message in clearProject, path must be a number');
  const indexedDBKeysToDelete: serviceWorkerIndex.IFilesRefInCache[] = await cacheIndex.getAllFilesRefInCache(projectID);
  const cache = await caches.open(CACHE_NAME);
  const cacheKeysToDelete = (await cache.keys()).filter(key => {
    const path = new URL(key.url).pathname;
    return path.startsWith(`/local/_${projectID}`);
  });
  console.log(`clearProject: project:${projectID} cache records=${cacheKeysToDelete.length}, indexedDB records=${indexedDBKeysToDelete.length}`);
  await Promise.all([
    ...cacheKeysToDelete.map(key => cache.delete(key)),
    ...indexedDBKeysToDelete.map(item => cacheIndex.deleteEntry(item.key))
  ]);
}


let findCatchJSCount = 0;
const findCacheJS = async (project: number, pathFile: string): Promise<string | null> => {
  const testExtension = ".test.js";
  const defsExtension = ".defs.js";
  const jsExtension = ".js";
  const tsExtension = ".ts";
  const isTestFile = pathFile.endsWith(testExtension);
  const isDefsFile = pathFile.endsWith(defsExtension);
  const isJsFile = pathFile.endsWith(jsExtension);
  const isTsFile = pathFile.endsWith(tsExtension);
  let extension = "";
  if (isTestFile) {
    extension = testExtension;
    pathFile = pathFile.slice(0, -testExtension.length)
  } else if (isDefsFile) {
    extension = defsExtension;
    pathFile = pathFile.slice(0, -defsExtension.length)
  } else if (isJsFile) {
    extension = jsExtension;
    pathFile = pathFile.slice(0, -jsExtension.length)
  } else if (isTsFile) {
    extension = tsExtension;
    pathFile = pathFile.slice(0, -tsExtension.length)
  } else {
    extension = ".js";
  }
  const url = await cacheIndex.getUrl(project, pathFile, extension);
  if (url) {
    if (mls.isTrace) console.info(`[ServiceWorker] findCacheJS rc: project=${project}, pathFile=${pathFile}, url=${url}`);
    return url;
  }
  if (mls.isTrace) console.info(`[ServiceWorker] findCacheJS 404 search=_${project}_${pathFile}${extension}`);
  return null;
}

/**
 * get url to use in fetch or return null if not in cache
  * @returns {Promise<string | null>} return path or null (don't in cache)
*/
const getURL = async (path: string, version: string): Promise<string | null> => {
  if (!path ||
    !version) throw new Error('No content or version in getURL');
  const cache = await caches.open(CACHE_NAME);
  const pathWithVersion = getPath(path, version);
  const matchedResponse = await cache.match(pathWithVersion);
  if (mls.isTrace) console.info(`[ServiceWorker] getURL  pathWithVersion=${pathWithVersion}, response:`, matchedResponse);
  if (!matchedResponse) return null;
  return pathWithVersion;
}

const getVersionFromUrl = (url: string): string => {
  return url.split("=").pop() || "";
}

export interface IServiceWorkerSts {
  versionSW: string;
  isTrace: boolean;
  totalRequests: number;
  totalHits: number;
  totalNotFound: number;
  totalInserts: number;
  baseProject: number;
}

/**
 * get statistics for development
 */
const getSTS = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<string> => {
  return new Promise<string>((resolve, reject) => {
    serviceWorkerIndex.get(tbName, MLSWORKERTRACE)
      .then((value) => {
        mls.isTrace = (value === 'true'); // update isTrace before get stats
        const result: IServiceWorkerSts = {
          versionSW: MLSSERVICEWORKERVERSION,
          isTrace: mls.isTrace,
          totalRequests: totalRequests,
          totalHits: totalHits,
          totalNotFound: totalNotFound,
          totalInserts: totalInserts,
          baseProject: baseProject
        };
        resolve(JSON.stringify(result));
      });
  });
}

const getPath = (path: string, version: string): string => {
  return `/local/${path}?v=${version}`;
}

const getPathWithoutVersion = (path: string): string => {
  // use to delete all versions
  return `/local/${path}`;
}

namespace cacheIndex {
  // pathFile , ex 'myFile' | '/folder1/myFile'
  const getKey = (project: number, pathFile: string, extension: string): string => {
    return `/local/_${project}_${pathFile}${extension}`;
  }

  export async function addWithExtension(project: number, pathFile: string, extension: string, version: string) {
    const key = getKey(project, pathFile, extension);
    addKey(key, version);
  }

  // key , ex '/myFile.js' | '/local/_100111_myFile.xx' | '/local/_100111_/folder1/myFile.xx'
  export async function addPath(path: string, version: string) {
    addKey(`/local/${path}`, version);
  }

  export const addPaths = async (paths: string[], versions: string[]) => {
    if (paths.length !== versions.length) throw new Error('addKeys, key and version must have the same length');
    const keys: string[] = paths.map((path, i) => `/local/${path}`);
    serviceWorkerIndex.setMultiple(tbName, keys, versions)
      .catch((reason) => {
        if (mls.isTrace) console.error(reason);
      });
  }

  // key , ex '/local/myFile.js' | '/local/_100111_myFile.xx' | '/local/_100111_/folder1/myFile.xx'
  const addKey = (key: string, version: string) => {
    // if (!version) return;
    serviceWorkerIndex.set(tbName, key, version)
      .catch((reason) => {
        if (mls.isTrace) console.error(reason);
      });
  }

  export async function deleteEntry(key: string) {
    return serviceWorkerIndex.set(tbName, key, ""); // remove entry
  }

  export async function getVersionFromPath(path: string): Promise<string | undefined> {
    return serviceWorkerIndex.get(tbName, `/local/${path}`)
  }

  export async function getAllFilesRefInCache(project: number | null): Promise<serviceWorkerIndex.IFilesRefInCache[]> {
    return serviceWorkerIndex.getAllFilesRefInCache(project);
  }

  export async function getUrl(project: number, pathFile: string, extension: string): Promise<string | undefined> {
    const key = getKey(project, pathFile, extension);
    const version = await serviceWorkerIndex.get(tbName, key);
    if (mls.isTrace && !version) console.log(`[ServiceWorker] getUrl, project=${project}, pathFile=${pathFile}, extension=${extension}, key=${key}, version=${version}`);
    if (!version) return undefined;
    return `${key}?v=${version}`;
  }

  export function getCacheUrl(record: serviceWorkerIndex.IFilesRefInCache): string {
    return `${record.key}?v=${record.value}`;
  }


  export function clear() {
    serviceWorkerIndex.clear(tbName);
  }
}

